// src/components/ZoneMap.js — Real Leaflet Interactive Map
import React, { useState, useEffect, useCallback, useRef } from "react";
import "leaflet/dist/leaflet.css";
import { MapContainer, TileLayer, CircleMarker, Popup, Marker, useMap } from "react-leaflet";
import L from "leaflet";
import { getZones, getResources } from "../services/api";
import "./ZoneMap.css";

// Fix Leaflet default icon issue in React
delete L.Icon.Default.prototype._getIconUrl;
L.Icon.Default.mergeOptions({
  iconRetinaUrl: "https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.9.4/images/marker-icon-2x.png",
  iconUrl: "https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.9.4/images/marker-icon.png",
  shadowUrl: "https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.9.4/images/marker-shadow.png",
});

// India bounding box — map coord_x/y (0–100%) to real lat/lng
const INDIA_LAT_MIN = 8.0;
const INDIA_LAT_MAX = 37.0;
const INDIA_LNG_MIN = 68.0;
const INDIA_LNG_MAX = 97.0;

function coordToLatLng(x, y) {
  const lat = INDIA_LAT_MAX - (y / 100) * (INDIA_LAT_MAX - INDIA_LAT_MIN);
  const lng = INDIA_LNG_MIN + (x / 100) * (INDIA_LNG_MAX - INDIA_LNG_MIN);
  return [lat, lng];
}

const SEV_COLOR   = { critical: "#EF4444", high: "#F59E0B", medium: "#3B82F6", low: "#10B981" };
const SEV_RADIUS  = { critical: 32, high: 24, medium: 18, low: 13 };
const TYPE_ICON   = { medical: "✚", rescue: "⬡", food: "◆", shelter: "▲" };
const TYPE_COLOR  = { medical: "#EF4444", rescue: "#F59E0B", food: "#10B981", shelter: "#3B82F6" };

// Mini component: auto-fit map to zone bounds
function FitBounds({ zones }) {
  const map = useMap();
  useEffect(() => {
    if (zones.length === 0) return;
    const bounds = zones.map((z) => coordToLatLng(z.coord_x, z.coord_y));
    if (bounds.length > 0) {
      map.fitBounds(bounds, { padding: [60, 60] });
    }
  }, [zones, map]);
  return null;
}

export default function ZoneMap({ tick }) {
  const [zones, setZones] = useState([]);
  const [resources, setResources] = useState([]);
  const [selected, setSelected] = useState(null);
  const [loading, setLoading] = useState(true);

  const fetchData = useCallback(async () => {
    try {
      const [zonesData, resourcesData] = await Promise.all([getZones(), getResources()]);
      setZones(zonesData);
      setResources(resourcesData);
      setLoading(false);
    } catch {
      setLoading(false);
    }
  }, []);

  useEffect(() => { fetchData(); }, [tick]);

  const deployedResources = resources.filter((r) => r.status === "deployed" && r.assigned_zone);

  const getPriorityColor = (score) => {
    if (score >= 65) return "#EF4444";
    if (score >= 50) return "#F59E0B";
    return "#3B82F6";
  };

  if (loading) {
    return (
      <div className="page" style={{ display: "flex", alignItems: "center", justifyContent: "center", minHeight: 400 }}>
        <div style={{ textAlign: "center", color: "var(--slate)" }}>
          <div className="analyze-spinner" style={{ margin: "0 auto 16px" }} />
          <div>Loading live map...</div>
        </div>
      </div>
    );
  }

  return (
    <div className="page">
      <div className="page-header">
        <h1>Disaster Zone Map</h1>
        <p>Real-time geographic view of all active disaster zones and deployed resources — India Region</p>
      </div>

      <div className="map-layout">
        {/* LEFT: Leaflet Map */}
        <div className="card map-card">
          <div className="map-header">
            <div className="card-title" style={{ marginBottom: 0 }}>Live Situation Map</div>
            <div className="map-meta">
              <span className="live-dot" />
              <span style={{ fontSize: 11, color: "var(--green)" }}>Live · OpenStreetMap</span>
              <span style={{ fontSize: 11, color: "var(--slate)", marginLeft: 8 }}>
                {zones.length} zones · {deployedResources.length} resources deployed
              </span>
            </div>
          </div>

          <div className="map-inner">
            <MapContainer
              center={[22.5, 82.5]}
              zoom={5}
              style={{ height: "100%", width: "100%" }}
              zoomControl={true}
              attributionControl={false}
            >
              <TileLayer
                url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
                attribution="© OpenStreetMap"
              />
              <FitBounds zones={zones} />

              {/* Disaster Zone markers */}
              {zones.map((zone) => {
                const pos = coordToLatLng(zone.coord_x, zone.coord_y);
                const color = SEV_COLOR[zone.severity] || "#3B82F6";
                const radius = SEV_RADIUS[zone.severity] || 16;
                const scoreColor = getPriorityColor(zone.priority_score);

                return (
                  <React.Fragment key={zone.id}>
                    {/* Outer pulse ring */}
                    <CircleMarker
                      center={pos}
                      radius={radius * 1.8}
                      pathOptions={{
                        color: color,
                        fillColor: color,
                        fillOpacity: 0.06,
                        weight: 1,
                        dashArray: "4 4",
                      }}
                    />
                    {/* Inner solid marker */}
                    <CircleMarker
                      center={pos}
                      radius={radius}
                      pathOptions={{
                        color: color,
                        fillColor: color,
                        fillOpacity: 0.25,
                        weight: 2,
                      }}
                      eventHandlers={{ click: () => setSelected(zone) }}
                    >
                      <Popup maxWidth={260} minWidth={220}>
                        <div className="popup-inner">
                          <div className="popup-title">{zone.name}</div>
                          <div className="popup-row">
                            <span>Type</span>
                            <span>{zone.disaster_type}</span>
                          </div>
                          <div className="popup-row">
                            <span>Severity</span>
                            <span style={{ color }}>{zone.severity.toUpperCase()}</span>
                          </div>
                          <div className="popup-row">
                            <span>Affected</span>
                            <span style={{ color: "#EF4444" }}>{zone.affected_count.toLocaleString()}</span>
                          </div>
                          <div className="popup-row">
                            <span>Resources</span>
                            <span>{zone.resources_deployed} deployed</span>
                          </div>
                          <div className="popup-score">
                            <span className="popup-score-num" style={{ color: scoreColor }}>
                              {zone.priority_score}
                            </span>
                            <span className="popup-score-label">AI Priority Score</span>
                          </div>
                        </div>
                      </Popup>
                    </CircleMarker>
                  </React.Fragment>
                );
              })}

              {/* Resource markers */}
              {deployedResources.map((res) => {
                const zone = zones.find((z) => z.id === res.assigned_zone);
                if (!zone) return null;
                const [lat, lng] = coordToLatLng(zone.coord_x, zone.coord_y);
                const offsets = { medical: [-0.4, -0.4], rescue: [0.4, -0.4], food: [-0.4, 0.4], shelter: [0.4, 0.4] };
                const [dlat, dlng] = offsets[res.resource_type] || [0, 0];
                const color = TYPE_COLOR[res.resource_type] || "#94A3B8";

                const icon = L.divIcon({
                  html: `<div style="
                    width:22px;height:22px;
                    border-radius:50%;
                    background:${color}22;
                    border:2px solid ${color};
                    display:flex;align-items:center;justify-content:center;
                    font-size:10px;
                    color:${color};
                    box-shadow:0 0 8px ${color}66;
                  ">${TYPE_ICON[res.resource_type]}</div>`,
                  className: "",
                  iconSize: [22, 22],
                  iconAnchor: [11, 11],
                });

                return (
                  <Marker
                    key={res.id}
                    position={[lat + dlat, lng + dlng]}
                    icon={icon}
                    title={res.name}
                  >
                    <Popup maxWidth={180}>
                      <div className="popup-inner">
                        <div className="popup-title">{res.name}</div>
                        <div className="popup-row"><span>Type</span><span>{res.resource_type}</span></div>
                        <div className="popup-row"><span>Status</span><span style={{ color }}>{res.status}</span></div>
                        <div className="popup-row"><span>Utilization</span><span>{res.utilized}/{res.capacity}</span></div>
                      </div>
                    </Popup>
                  </Marker>
                );
              })}
            </MapContainer>
          </div>

          {/* Bottom legend */}
          <div style={{ display: "flex", gap: 20, padding: "10px 20px", borderTop: "1px solid var(--glass-border)", flexShrink: 0 }}>
            <div style={{ display: "flex", gap: 12, alignItems: "center" }}>
              <span style={{ fontSize: 10, color: "var(--slate)", letterSpacing: "0.08em", textTransform: "uppercase" }}>Severity:</span>
              {Object.entries(SEV_COLOR).map(([k, v]) => (
                <div key={k} style={{ display: "flex", alignItems: "center", gap: 5, fontSize: 11 }}>
                  <div style={{ width: 8, height: 8, borderRadius: "50%", background: v, boxShadow: `0 0 6px ${v}` }} />
                  <span style={{ color: "var(--slate)", textTransform: "capitalize" }}>{k}</span>
                </div>
              ))}
            </div>
            <div style={{ display: "flex", gap: 12, alignItems: "center" }}>
              <span style={{ fontSize: 10, color: "var(--slate)", letterSpacing: "0.08em", textTransform: "uppercase" }}>Resources:</span>
              {Object.entries(TYPE_ICON).map(([k, v]) => (
                <div key={k} style={{ display: "flex", alignItems: "center", gap: 5, fontSize: 11 }}>
                  <span style={{ color: TYPE_COLOR[k] }}>{v}</span>
                  <span style={{ color: "var(--slate)", textTransform: "capitalize" }}>{k}</span>
                </div>
              ))}
            </div>
          </div>
        </div>

        {/* RIGHT: Side panel */}
        <div className="map-side">
          {selected ? (
            <div className="card">
              <div className="card-title">Zone Detail</div>
              <div className="mz-name">{selected.name}</div>
              <div style={{ display: "flex", gap: 8, margin: "10px 0" }}>
                <span className={`badge badge-${selected.severity}`}>{selected.severity}</span>
                <span className="badge badge-medium">{selected.disaster_type}</span>
              </div>

              {/* Priority score big display */}
              <div style={{
                textAlign: "center", padding: "14px", marginBottom: 14,
                background: "rgba(59,130,246,0.08)",
                border: "1px solid rgba(59,130,246,0.2)",
                borderRadius: 9,
              }}>
                <div style={{
                  fontSize: 40, fontWeight: 700, fontFamily: "var(--font-display)",
                  color: getPriorityColor(selected.priority_score),
                  textShadow: `0 0 20px ${getPriorityColor(selected.priority_score)}55`,
                }}>
                  {selected.priority_score}
                </div>
                <div style={{ fontSize: 10, color: "var(--slate)", letterSpacing: "0.08em", textTransform: "uppercase", marginTop: 2 }}>
                  AI Priority Score
                </div>
              </div>

              <div className="mz-stats">
                <div className="mz-stat">
                  <div className="mz-stat-label">Affected</div>
                  <div className="mz-stat-val" style={{ color: "#EF4444", fontSize: 16 }}>{(selected.affected_count / 1000).toFixed(1)}k</div>
                </div>
                <div className="mz-stat">
                  <div className="mz-stat-label">Population</div>
                  <div className="mz-stat-val" style={{ fontSize: 16 }}>{(selected.population / 1000).toFixed(0)}k</div>
                </div>
                <div className="mz-stat">
                  <div className="mz-stat-label">Resources</div>
                  <div className="mz-stat-val" style={{ color: "#3B82F6", fontSize: 16 }}>{selected.resources_deployed}</div>
                </div>
              </div>

              <div style={{ marginTop: 16 }}>
                <div className="card-title" style={{ marginBottom: 10 }}>Needs Assessment</div>
                {[["medical", selected.need_medical], ["food", selected.need_food], ["shelter", selected.need_shelter], ["rescue", selected.need_rescue]].map(([k, v]) => (
                  <div key={k} className="need-row">
                    <span className="need-label" style={{ textTransform: "capitalize" }}>{k}</span>
                    <div className="need-track">
                      <div className="need-fill" style={{ width: `${v}%`, background: v >= 75 ? "#EF4444" : v >= 50 ? "#F59E0B" : "#3B82F6" }} />
                    </div>
                    <span className="need-pct">{v}%</span>
                  </div>
                ))}
              </div>

              <div style={{ marginTop: 16 }}>
                <div className="card-title" style={{ marginBottom: 10 }}>Deployed Resources</div>
                {resources.filter((r) => r.assigned_zone === selected.id).map((r) => (
                  <div key={r.id} className="mz-resource">
                    <span className="mz-res-icon" style={{ color: TYPE_COLOR[r.resource_type] }}>{TYPE_ICON[r.resource_type]}</span>
                    <div style={{ flex: 1 }}>
                      <div style={{ fontSize: 12, fontWeight: 500 }}>{r.name}</div>
                      <div style={{ fontSize: 11, color: "var(--slate)" }}>{r.utilized}/{r.capacity} utilized</div>
                    </div>
                    <span className={`badge badge-${r.status}`}>{r.status}</span>
                  </div>
                ))}
                {resources.filter((r) => r.assigned_zone === selected.id).length === 0 && (
                  <div style={{ fontSize: 12, color: "var(--slate-dim)" }}>No resources currently assigned</div>
                )}
              </div>

              <button className="btn btn-ghost btn-sm" style={{ marginTop: 14, width: "100%", justifyContent: "center" }} onClick={() => setSelected(null)}>
                ← Back to zone list
              </button>
            </div>
          ) : (
            <>
              <div className="card">
                <div className="card-title">Active Zones</div>
                <div style={{ fontSize: 12, color: "var(--slate)", marginBottom: 12 }}>
                  Click any zone marker or select below for details.
                </div>
                <div className="zones-summary">
                  {[...zones].sort((a, b) => b.priority_score - a.priority_score).map((z) => (
                    <div key={z.id} className="zone-sum-row" onClick={() => setSelected(z)}>
                      <div className="zone-sum-dot" style={{ background: SEV_COLOR[z.severity], boxShadow: `0 0 6px ${SEV_COLOR[z.severity]}` }} />
                      <div style={{ flex: 1 }}>
                        <div style={{ fontSize: 12, fontWeight: 500 }}>{z.disaster_type} — {z.name.split("—")[0].trim()}</div>
                        <div style={{ fontSize: 10, color: "var(--slate-dim)" }}>
                          {z.affected_count.toLocaleString()} affected · Score: <span style={{ color: getPriorityColor(z.priority_score) }}>{z.priority_score}</span>
                        </div>
                      </div>
                      <span className={`badge badge-${z.severity}`}>{z.severity}</span>
                    </div>
                  ))}
                </div>
              </div>

              {/* Zone stats summary */}
              <div className="card">
                <div className="card-title">Map Summary</div>
                {[
                  { label: "Critical Zones", val: zones.filter((z) => z.severity === "critical").length, color: "#EF4444" },
                  { label: "High Zones", val: zones.filter((z) => z.severity === "high").length, color: "#F59E0B" },
                  { label: "Resources Deployed", val: deployedResources.length, color: "#10B981" },
                  { label: "Total Affected", val: zones.reduce((s, z) => s + z.affected_count, 0).toLocaleString(), color: "#3B82F6" },
                ].map((item) => (
                  <div key={item.label} style={{ display: "flex", justifyContent: "space-between", alignItems: "center", padding: "8px 0", borderBottom: "1px solid rgba(255,255,255,0.04)", fontSize: 12 }}>
                    <span style={{ color: "var(--slate)" }}>{item.label}</span>
                    <span style={{ fontWeight: 700, color: item.color, fontFamily: "var(--font-display)" }}>{item.val}</span>
                  </div>
                ))}
              </div>
            </>
          )}
        </div>
      </div>
    </div>
  );
}
